CREATE TABLE IF NOT EXISTS public.cctv_info
(
    cctv_id character varying(50) COLLATE pg_catalog."default" NOT NULL,
    cctv_name character varying(200) COLLATE pg_catalog."default" NOT NULL,
    road_name character varying(200) COLLATE pg_catalog."default",
    latitude numeric(10, 8),
    longitude numeric(11, 8),
    stream_url character varying(500) COLLATE pg_catalog."default",
    district character varying(50) COLLATE pg_catalog."default",
    is_active boolean,
    updated_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT cctv_info_pkey PRIMARY KEY (cctv_id)
);

CREATE TABLE IF NOT EXISTS public.equipment
(
    equipment_id bigserial NOT NULL,
    intersection_id bigint NOT NULL,
    equipment_type character varying(50) COLLATE pg_catalog."default" NOT NULL,
    status character varying(20) COLLATE pg_catalog."default" DEFAULT 'NORMAL'::character varying,
    installation_date date,
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT equipment_pkey PRIMARY KEY (equipment_id)
);

CREATE TABLE IF NOT EXISTS public.intersection
(
    intersection_id bigserial NOT NULL,
    name character varying(100) COLLATE pg_catalog."default" NOT NULL,
    latitude numeric(10, 8),
    longitude numeric(11, 8),
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT intersection_pkey PRIMARY KEY (intersection_id)
);

CREATE TABLE IF NOT EXISTS public.its_collect_log
(
    log_id bigserial NOT NULL,
    collect_type character varying(20) COLLATE pg_catalog."default" NOT NULL,
    status character varying(20) COLLATE pg_catalog."default" NOT NULL,
    total_count integer,
    new_count integer,
    error_message text COLLATE pg_catalog."default",
    executed_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT its_collect_log_pkey PRIMARY KEY (log_id)
);

CREATE TABLE IF NOT EXISTS public.its_route
(
    route_id bigserial NOT NULL,
    route_no character varying(10) COLLATE pg_catalog."default" NOT NULL,
    route_name character varying(100) COLLATE pg_catalog."default",
    collect_up boolean,
    collect_down boolean,
    is_active boolean DEFAULT true,
    memo character varying(200) COLLATE pg_catalog."default",
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    updated_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT its_route_pkey PRIMARY KEY (route_id),
    CONSTRAINT its_route_route_no_key UNIQUE (route_no)
);

CREATE TABLE IF NOT EXISTS public.maintenance_log
(
    ticket_id bigserial NOT NULL,
    equipment_id bigint NOT NULL,
    repair_status character varying(20) COLLATE pg_catalog."default" DEFAULT 'REQUESTED'::character varying,
    reported_by character varying(50) COLLATE pg_catalog."default",
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    resolved_at timestamp without time zone,
    CONSTRAINT maintenance_log_pkey PRIMARY KEY (ticket_id)
);

CREATE TABLE IF NOT EXISTS public.member
(
    member_id bigserial NOT NULL,
    login_id character varying(50) COLLATE pg_catalog."default" NOT NULL,
    password character varying(255) COLLATE pg_catalog."default" NOT NULL,
    name character varying(50) COLLATE pg_catalog."default" NOT NULL,
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    email character varying(255) COLLATE pg_catalog."default" NOT NULL,
    CONSTRAINT member_pkey PRIMARY KEY (member_id),
    CONSTRAINT member_email_key UNIQUE (email),
    CONSTRAINT member_login_id_key UNIQUE (login_id)
);

CREATE TABLE IF NOT EXISTS public.sensor_log
(
    log_id bigserial NOT NULL,
    equipment_id bigint NOT NULL,
    temperature numeric(6, 2),
    vibration numeric(6, 2),
    risk_score numeric(3, 2),
    recorded_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    motor_current numeric(6, 2),
    CONSTRAINT sensor_log_pkey PRIMARY KEY (log_id)
);

CREATE TABLE IF NOT EXISTS public.signal_control_log
